const incident = $('Normalize Incident Data').first().json;
const runbookRaw = $input.first().json;

let runbookContext = '';
try {
  if (runbookRaw && runbookRaw.Service) {
    const parts = [];
    if (runbookRaw['Known Issues']) parts.push('Known issues: ' + runbookRaw['Known Issues']);
    if (runbookRaw['First Response Steps']) parts.push('First response: ' + runbookRaw['First Response Steps']);
    if (runbookRaw['Escalation Contact']) parts.push('Escalation contact: ' + runbookRaw['Escalation Contact']);
    if (runbookRaw['SLA Minutes']) parts.push('SLA target: ' + runbookRaw['SLA Minutes'] + ' minutes');
    runbookContext = parts.join('. ');
  }
} catch (e) {
  runbookContext = '';
}

return [{
  json: {
    ...incident,
    runbookContext: runbookContext || 'No runbook found for this service.'
  }
}];

// Updated 2026-03-22: Added robust JSON fence stripping
// after Gemini started wrapping responses in markdown

const analyzerResponse = $input.first().json.output || $input.first().json.text || '';

let cleanedResponse = analyzerResponse.trim();

// Strip markdown code fences
if (cleanedResponse.startsWith('```json')) {
  cleanedResponse = cleanedResponse.slice(7);
}
if (cleanedResponse.startsWith('```')) {
  cleanedResponse = cleanedResponse.slice(3);
}
if (cleanedResponse.endsWith('```')) {
  cleanedResponse = cleanedResponse.slice(0, -3);
}
cleanedResponse = cleanedResponse.trim();

// Try to extract JSON from mixed text
if (!cleanedResponse.startsWith('{')) {
  const jsonMatch = cleanedResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cleanedResponse = jsonMatch[0];
  }
}

const incident = $('Build Runbook Context').first().json;

try {
  const analysis = JSON.parse(cleanedResponse);

  // Validate required fields
  const hasRequiredFields = 
    analysis.severity && 
    typeof analysis.confidence === 'number' &&
    analysis.reasoning &&
    Array.isArray(analysis.risk_indicators);

  if (!hasRequiredFields) {
    throw new Error('Missing required fields in analysis');
  }

  // Validate severity is one of P1/P2/P3
  if (!['P1', 'P2', 'P3'].includes(analysis.severity)) {
    throw new Error('Invalid severity value: ' + analysis.severity);
  }

  return {
    json: {
      ...incident,
      analysis: analysis,
      parseSuccess: true,
      analyzerModel: 'gemini'
    }
  };

} catch (error) {
  // Complete fallback - use reported severity
  return {
    json: {
      ...incident,
      analysis: {
        severity: incident.reportedSeverity,
        confidence: 0.0,
        reasoning: 'Analyzer failed - using reported severity. Error: ' + error.message,
        risk_indicators: [],
        matches_known_issue: false,
        urgency_score: 5
      },
      parseSuccess: false,
      parseError: error.message,
      rawResponse: analyzerResponse
    }
  };
}

