// Parse Response Coordinator output

const coordinatorResponse = $input.first().json.output || $input.first().json.text || '';

let cleanedResponse = coordinatorResponse.trim();

// Strip markdown fences
if (cleanedResponse.startsWith('```json')) {
  cleanedResponse = cleanedResponse.slice(7);
}
if (cleanedResponse.startsWith('```')) {
  cleanedResponse = cleanedResponse.slice(3);
}
if (cleanedResponse.endsWith('```')) {
  cleanedResponse = cleanedResponse.slice(0, -3);
}
cleanedResponse = cleanedResponse.trim();

// Extract JSON from mixed text
if (!cleanedResponse.startsWith('{')) {
  const jsonMatch = cleanedResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cleanedResponse = jsonMatch[0];
  }
}

const incident = $('Parse Analyzer Output').first().json;
const analysis = incident.analysis;

try {
  const plan = JSON.parse(cleanedResponse);

  // Validate required fields
  const hasRequiredFields = 
    Array.isArray(plan.immediate_actions) &&
    plan.escalation_tier &&
    Array.isArray(plan.notification_channels) &&
    typeof plan.sla_minutes === 'number';

  if (!hasRequiredFields) {
    throw new Error('Missing required fields in response plan');
  }

  // Calculate severity override flag
  const severityChanged = analysis.severity !== incident.reportedSeverity;

  return {
    json: {
      incidentId: incident.incidentId,
      title: incident.title,
      description: incident.description,
      service: incident.service,
      reporter: incident.reporter,
      reportedAt: incident.reportedAt,
      status: incident.status,

      // Original data
      reportedSeverity: incident.reportedSeverity,
      runbookContext: incident.runbookContext,

      // AI Analysis (Agent 1)
      severity: analysis.severity,
      confidence: analysis.confidence,
      reasoning: analysis.reasoning,
      risk_indicators: analysis.risk_indicators.join('; '),
      matches_known_issue: analysis.matches_known_issue,
      urgency_score: analysis.urgency_score,

      // Response Plan (Agent 2)
      immediate_actions: plan.immediate_actions.join('; '),
      escalation_tier: plan.escalation_tier,
      notification_channels: plan.notification_channels.join(', '),
      sla_minutes: plan.sla_minutes,
      root_cause_hypothesis: plan.root_cause_hypothesis || '',
      requires_war_room: plan.requires_war_room,
      recommended_assignee: plan.recommended_assignee || '',

      // Audit fields
      severityOverridden: severityChanged,
      analyzerSuccess: incident.parseSuccess,
      coordinatorSuccess: true
    }
  };

} catch (error) {
  // Fallback plan generation
  const defaultSLA = {
    'P1': 15,
    'P2': 60,
    'P3': 240
  };

  return {
    json: {
      incidentId: incident.incidentId,
      title: incident.title,
      description: incident.description,
      service: incident.service,
      reporter: incident.reporter,
      reportedAt: incident.reportedAt,
      status: incident.status,
      reportedSeverity: incident.reportedSeverity,
      runbookContext: incident.runbookContext,

      severity: analysis.severity,
      confidence: analysis.confidence,
      reasoning: analysis.reasoning,
      risk_indicators: analysis.risk_indicators.join('; '),
      matches_known_issue: analysis.matches_known_issue,
      urgency_score: analysis.urgency_score,

      // Fallback plan
      immediate_actions: 'Investigate manually - coordinator failed',
      escalation_tier: analysis.severity === 'P1' ? 'manager' : 'team',
      notification_channels: analysis.severity === 'P1' ? '#incidents-critical' : '#incidents',
      sla_minutes: defaultSLA[analysis.severity] || 60,
      root_cause_hypothesis: 'Requires manual investigation',
      requires_war_room: analysis.severity === 'P1',
      recommended_assignee: 'On-call engineer',

      severityOverridden: analysis.severity !== incident.reportedSeverity,
      analyzerSuccess: incident.parseSuccess,
      coordinatorSuccess: false,
      coordinatorError: error.message
    }
  };
}

